package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.lang.reflect.Field;
import java.util.Date;

class DefaultDateTypeAdapterTest {

    private DefaultDateTypeAdapter<Date> adapter;
    private DefaultDateTypeAdapter.DateType<Date> dateTypeMock;

    @BeforeEach
    void setUp() throws Exception {
        dateTypeMock = mock(DefaultDateTypeAdapter.DateType.class);
        // Use explicit type argument to fix type inference error
        adapter = new DefaultDateTypeAdapter<Date>(dateTypeMock, "yyyy-MM-dd");
    }

    @Test
    void read_shouldReturnNull_whenJsonTokenIsNull() throws IOException {
        JsonReader jsonReader = mock(JsonReader.class);
        when(jsonReader.peek()).thenReturn(JsonToken.NULL);

        // nextNull returns void, so just do nothing on call
        doNothing().when(jsonReader).nextNull();

        Date result = adapter.read(jsonReader);

        verify(jsonReader).peek();
        verify(jsonReader).nextNull();
        assertNull(result);
    }

    @Test
    void read_shouldDeserializeDateAndReturnDeserializedValue() throws Exception {
        JsonReader jsonReader = mock(JsonReader.class);
        when(jsonReader.peek()).thenReturn(JsonToken.STRING);

        // Prepare a Date instance to be returned by deserializeToDate
        Date dateInstance = new Date();

        // Use reflection to set private method deserializeToDate behavior by injecting a spy of adapter with overridden method
        // Since deserializeToDate is private and cannot be mocked directly, we replace adapter with a spy and override deserializeToDate via reflection

        // Create a spy of adapter
        DefaultDateTypeAdapter<Date> spyAdapter = Mockito.spy(adapter);

        // Use reflection to get the private method deserializeToDate
        java.lang.reflect.Method deserializeToDateMethod = DefaultDateTypeAdapter.class.getDeclaredMethod("deserializeToDate", JsonReader.class);
        deserializeToDateMethod.setAccessible(true);

        // Use reflection to override deserializeToDate method by using a proxy via java.lang.reflect.Proxy is not possible here
        // Instead, replace the private method by using a wrapper spy with doAnswer
        // But since method is private, Mockito cannot mock it directly
        // So we use a trick: override the method by subclassing and injecting the spyAdapter with an anonymous subclass

        DefaultDateTypeAdapter<Date> adapterWithOverride = new DefaultDateTypeAdapter<Date>(dateTypeMock, "yyyy-MM-dd") {
            @Override
            public Date read(JsonReader in) throws IOException {
                if (in.peek() == JsonToken.NULL) {
                    in.nextNull();
                    return null;
                }
                // return our dateInstance directly instead of calling deserializeToDate
                return dateTypeMock.deserialize(dateInstance);
            }
        };

        // But we want to test the original read method, so instead, we do this:

        // Use reflection to replace the private method deserializeToDate with a lambda is impossible.
        // So instead, use reflection to replace the private method with a Field holding a callable is impossible.
        // So we call read on spyAdapter, but stub deserializeToDate via reflection:

        // Use reflection to set accessible the private deserializeToDate method
        // Then use Mockito doReturn on spyAdapter with a workaround:
        // We create a helper subclass to expose deserializeToDate as protected for mocking

        // Alternative approach: Use reflection to invoke deserializeToDate and stub dateType.deserialize

        // So we skip mocking deserializeToDate and instead mock dateType.deserialize to accept the date returned by deserializeToDate

        // Invoke the private method deserializeToDate directly on spyAdapter to get the Date to return
        Date deserializedDateFromPrivateMethod = (Date) deserializeToDateMethod.invoke(spyAdapter, jsonReader);

        // Now mock dateTypeMock.deserialize to return a modified date
        Date deserializedDate = new Date(deserializedDateFromPrivateMethod.getTime() + 1000);
        when(dateTypeMock.deserialize(deserializedDateFromPrivateMethod)).thenReturn(deserializedDate);

        // Now call read on spyAdapter
        Date result = spyAdapter.read(jsonReader);

        verify(jsonReader).peek();
        verify(dateTypeMock).deserialize(deserializedDateFromPrivateMethod);
        assertEquals(deserializedDate, result);
    }
}
